# -*- coding: utf-8 -*-
"""
PriceBot Final Enterprise - Single File Edition
Generated as one app.py file for simple GitHub upload.
Contains the same enterprise fixes: async webhook, SQLite state/settings, sessions, CSRF, SQL product search.
"""

import sys as _sys
import types as _types

# Allow this single app.py to behave like a package named `app` so internal modules can use relative imports.
if __name__ == "app":
    __path__ = []  # type: ignore
    _pkg = _sys.modules[__name__]
else:
    _pkg = _types.ModuleType("app")
    _pkg.__path__ = []
    _sys.modules["app"] = _pkg


def _install_module(_name: str, _source: str):
    _fullname = f"app.{_name}"
    _mod = _types.ModuleType(_fullname)
    _mod.__package__ = "app"
    _mod.__file__ = f"<single-file:{_fullname}>"
    _sys.modules[_fullname] = _mod
    setattr(_pkg, _name, _mod)
    exec(compile(_source, _mod.__file__, "exec"), _mod.__dict__)
    return _mod


# ===== embedded module: app.config =====
_install_module('config', 'from __future__ import annotations\n\nimport os\nfrom dataclasses import dataclass\nfrom pathlib import Path\nfrom dotenv import load_dotenv\n\nBASE_DIR = Path(__file__).resolve().parent.parent\nload_dotenv(BASE_DIR / ".env")\nload_dotenv()\n\n\ndef env(name: str, default: str = "") -> str:\n    return (os.getenv(name, default) or default).strip()\n\n\n@dataclass(frozen=True)\nclass Config:\n    app_name: str = "PriceBot"\n    base_dir: Path = BASE_DIR\n    data_dir: Path = BASE_DIR / "data"\n    upload_dir: Path = BASE_DIR / "uploads"\n    db_path: Path = BASE_DIR / "pricebot.db"\n    session_secret: str = env("SESSION_SECRET", env("ADMIN_KEY", "PriceBotAdmin2026"))\n    admin_password: str = env("ADMIN_PASSWORD", env("ADMIN_KEY", "PriceBotAdmin2026"))\n    merchant_code: str = env("MERCHANT_ACCESS_CODE", env("MERCHANT_CODE", "BADR2026"))\n    whatsapp_verify_token: str = env("WHATSAPP_VERIFY_TOKEN", env("VERIFY_TOKEN", ""))\n    whatsapp_token: str = env("WHATSAPP_TOKEN", env("META_WHATSAPP_TOKEN", ""))\n    whatsapp_phone_number_id: str = env("WHATSAPP_PHONE_NUMBER_ID", env("PHONE_NUMBER_ID", ""))\n    default_customer_number: str = env("CUSTOMER_WHATSAPP_NUMBER", env("WHATSAPP_DISPLAY_NUMBER", "218918874659"))\n    openrouter_keys: str = env("AI_OPENROUTER_KEYS", env("OPENROUTER_API_KEY", ""))\n    gemini_keys: str = env("AI_GEMINI_KEYS", env("GEMINI_API_KEY", ""))\n    groq_keys: str = env("AI_GROQ_KEYS", env("GROQ_API_KEY", ""))\n    openai_keys: str = env("AI_OPENAI_KEYS", env("OPENAI_API_KEY", ""))\n    provider_order: str = env("AI_PROVIDER_ORDER", "gemini,openrouter,groq,openai")\n    ai_enabled: bool = env("AI_ENABLED", "yes").lower() in {"1", "true", "yes", "on"}\n    daily_report_hour: int = int(env("DAILY_REPORT_HOUR", "21") or "21")\n\n\nconfig = Config()\nconfig.data_dir.mkdir(parents=True, exist_ok=True)\nconfig.upload_dir.mkdir(parents=True, exist_ok=True)\n')

# ===== embedded module: app.normalize =====
_install_module('normalize', 'from __future__ import annotations\n\nimport re\n\n_ARABIC_MAP = str.maketrans({\n    "أ": "ا", "إ": "ا", "آ": "ا", "ى": "ي", "ئ": "ي", "ؤ": "و", "ة": "ه",\n    "َ": "", "ً": "", "ُ": "", "ٌ": "", "ِ": "", "ٍ": "", "ْ": "", "ّ": "",\n})\n\nSTOP_WORDS = {\n    "عندكم", "متوفر", "موجود", "كم", "سعر", "السعر", "نبي", "ابي", "ابى", "اريد", "ممكن",\n    "هل", "في", "فيه", "دواء", "منتج", "حبوب", "شراب", "علبه", "علبة", "شريط", "لوسمحت", "لو سمحت",\n}\n\n\ndef normalize(text: str | None) -> str:\n    s = (text or "").lower().strip().translate(_ARABIC_MAP)\n    s = re.sub(r"[^\\w\\s\\u0600-\\u06ff./+-]+", " ", s)\n    s = re.sub(r"\\s+", " ", s).strip()\n    return s\n\n\ndef query_tokens(text: str) -> list[str]:\n    words = [w for w in normalize(text).split() if len(w) > 1]\n    return [w for w in words if w not in STOP_WORDS]\n\n\ndef norm_blob(*parts: object) -> str:\n    return normalize(" ".join(str(p or "") for p in parts))\n')

# ===== embedded module: app.db =====
_install_module('db', 'from __future__ import annotations\n\nimport json\nimport time\nfrom typing import Any, Iterable\nimport aiosqlite\nfrom contextlib import asynccontextmanager\n\nfrom .config import config\n\n\n@asynccontextmanager\nasync def connect():\n    db = await aiosqlite.connect(config.db_path, timeout=30)\n    db.row_factory = aiosqlite.Row\n    await db.execute("PRAGMA journal_mode=WAL")\n    await db.execute("PRAGMA busy_timeout=30000")\n    await db.execute("PRAGMA foreign_keys=ON")\n    try:\n        yield db\n    finally:\n        await db.close()\n\n\nasync def init_db() -> None:\n    async with connect() as db:\n        await db.executescript(\n            """\n            CREATE TABLE IF NOT EXISTS settings (\n                key TEXT PRIMARY KEY,\n                value TEXT NOT NULL DEFAULT \'\'\n            );\n\n            CREATE TABLE IF NOT EXISTS products (\n                id INTEGER PRIMARY KEY AUTOINCREMENT,\n                name TEXT NOT NULL,\n                aliases TEXT DEFAULT \'\',\n                active_ingredient TEXT DEFAULT \'\',\n                company TEXT DEFAULT \'\',\n                form TEXT DEFAULT \'\',\n                strength TEXT DEFAULT \'\',\n                pack TEXT DEFAULT \'\',\n                price TEXT DEFAULT \'\',\n                available TEXT DEFAULT \'متوفر\',\n                notes TEXT DEFAULT \'\',\n                image TEXT DEFAULT \'\',\n                norm_blob TEXT DEFAULT \'\',\n                updated_at INTEGER NOT NULL DEFAULT 0\n            );\n            CREATE INDEX IF NOT EXISTS idx_products_name ON products(name);\n            CREATE INDEX IF NOT EXISTS idx_products_active ON products(active_ingredient);\n            CREATE INDEX IF NOT EXISTS idx_products_norm ON products(norm_blob);\n\n            CREATE TABLE IF NOT EXISTS orders (\n                id INTEGER PRIMARY KEY AUTOINCREMENT,\n                phone TEXT NOT NULL,\n                product_id INTEGER,\n                product_name TEXT NOT NULL,\n                price TEXT DEFAULT \'\',\n                notes TEXT DEFAULT \'\',\n                status TEXT NOT NULL DEFAULT \'pending\',\n                raw_message TEXT DEFAULT \'\',\n                media_url TEXT DEFAULT \'\',\n                created_at INTEGER NOT NULL,\n                updated_at INTEGER NOT NULL\n            );\n            CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);\n            CREATE INDEX IF NOT EXISTS idx_orders_phone ON orders(phone);\n            CREATE INDEX IF NOT EXISTS idx_orders_created ON orders(created_at);\n\n            CREATE TABLE IF NOT EXISTS conversation_state (\n                namespace TEXT NOT NULL,\n                user_key TEXT NOT NULL,\n                value_json TEXT NOT NULL,\n                updated_at INTEGER NOT NULL,\n                PRIMARY KEY(namespace, user_key)\n            );\n\n            CREATE TABLE IF NOT EXISTS product_inquiries (\n                id INTEGER PRIMARY KEY AUTOINCREMENT,\n                phone TEXT DEFAULT \'\',\n                raw_text TEXT DEFAULT \'\',\n                query TEXT DEFAULT \'\',\n                product_id INTEGER,\n                product_name TEXT DEFAULT \'\',\n                found INTEGER NOT NULL DEFAULT 0,\n                created_at INTEGER NOT NULL\n            );\n            CREATE INDEX IF NOT EXISTS idx_inquiries_created ON product_inquiries(created_at);\n            CREATE INDEX IF NOT EXISTS idx_inquiries_product ON product_inquiries(product_name);\n\n            CREATE TABLE IF NOT EXISTS cache (\n                namespace TEXT NOT NULL,\n                cache_key TEXT NOT NULL,\n                value_json TEXT NOT NULL,\n                updated_at INTEGER NOT NULL,\n                PRIMARY KEY(namespace, cache_key)\n            );\n\n            CREATE TABLE IF NOT EXISTS ai_usage (\n                day TEXT PRIMARY KEY,\n                count INTEGER NOT NULL DEFAULT 0\n            );\n            """\n        )\n        defaults = {\n            "PHARMACY_NAME": "صيدلية بدر البشرية",\n            "PHARMACY_CITY": "أجدابيا",\n            "PHARMACY_HOURS": "24 ساعة",\n            "DELIVERY_TEXT": "التوصيل غير متوفر حالياً",\n            "DELIVERY_AVAILABLE": "no",\n            "CUSTOMER_WHATSAPP_NUMBER": config.default_customer_number,\n            "ADMIN_NOTIFY_PHONE": "",\n        }\n        for key, value in defaults.items():\n            await db.execute("INSERT OR IGNORE INTO settings(key, value) VALUES (?, ?)", (key, value))\n        await db.commit()\n\n\nasync def get_setting(key: str, default: str = "") -> str:\n    async with connect() as db:\n        cur = await db.execute("SELECT value FROM settings WHERE key=?", (key,))\n        row = await cur.fetchone()\n        return str(row[0]) if row else default\n\n\nasync def get_settings() -> dict[str, str]:\n    async with connect() as db:\n        rows = await db.execute_fetchall("SELECT key,value FROM settings")\n        return {str(r[0]): str(r[1]) for r in rows}\n\n\nasync def set_settings(values: dict[str, str]) -> None:\n    async with connect() as db:\n        for key, value in values.items():\n            await db.execute(\n                "INSERT INTO settings(key,value) VALUES (?,?) ON CONFLICT(key) DO UPDATE SET value=excluded.value",\n                (str(key), str(value)),\n            )\n        await db.commit()\n\n\nasync def set_state(namespace: str, user_key: str, value: Any) -> None:\n    payload = json.dumps(value, ensure_ascii=False)\n    now = int(time.time())\n    async with connect() as db:\n        await db.execute(\n            """\n            INSERT INTO conversation_state(namespace,user_key,value_json,updated_at)\n            VALUES (?,?,?,?)\n            ON CONFLICT(namespace,user_key) DO UPDATE SET value_json=excluded.value_json, updated_at=excluded.updated_at\n            """,\n            (namespace, user_key, payload, now),\n        )\n        await db.commit()\n\n\nasync def get_state(namespace: str, user_key: str, default: Any = None) -> Any:\n    async with connect() as db:\n        cur = await db.execute(\n            "SELECT value_json FROM conversation_state WHERE namespace=? AND user_key=?",\n            (namespace, user_key),\n        )\n        row = await cur.fetchone()\n    if not row:\n        return default\n    try:\n        return json.loads(row[0])\n    except Exception:\n        return default\n\n\nasync def delete_state(namespace: str, user_key: str) -> None:\n    async with connect() as db:\n        await db.execute("DELETE FROM conversation_state WHERE namespace=? AND user_key=?", (namespace, user_key))\n        await db.commit()\n\n\nasync def get_cache(namespace: str, cache_key: str, default: Any = None) -> Any:\n    async with connect() as db:\n        cur = await db.execute("SELECT value_json FROM cache WHERE namespace=? AND cache_key=?", (namespace, cache_key))\n        row = await cur.fetchone()\n    if not row:\n        return default\n    try:\n        return json.loads(row[0])\n    except Exception:\n        return default\n\n\nasync def set_cache(namespace: str, cache_key: str, value: Any) -> None:\n    payload = json.dumps(value, ensure_ascii=False)\n    now = int(time.time())\n    async with connect() as db:\n        await db.execute(\n            """\n            INSERT INTO cache(namespace,cache_key,value_json,updated_at)\n            VALUES (?,?,?,?)\n            ON CONFLICT(namespace,cache_key) DO UPDATE SET value_json=excluded.value_json, updated_at=excluded.updated_at\n            """,\n            (namespace, cache_key, payload, now),\n        )\n        await db.commit()\n')

# ===== embedded module: app.security =====
_install_module('security', 'from __future__ import annotations\n\nimport secrets\nimport time\nfrom typing import Literal\nfrom itsdangerous import URLSafeSerializer, BadSignature\nfrom fastapi import Request, HTTPException\nfrom fastapi.responses import Response, RedirectResponse\n\nfrom .config import config\n\nserializer = URLSafeSerializer(config.session_secret, salt="pricebot-session-v2")\n\nSESSION_COOKIE = "pricebot_session"\nCSRF_COOKIE = "pricebot_csrf"\nRole = Literal["admin", "merchant"]\n\n\ndef make_session(role: Role) -> str:\n    return serializer.dumps({"role": role, "iat": int(time.time()), "nonce": secrets.token_urlsafe(12)})\n\n\ndef read_session(request: Request) -> dict | None:\n    raw = request.cookies.get(SESSION_COOKIE)\n    if not raw:\n        return None\n    try:\n        data = serializer.loads(raw)\n    except BadSignature:\n        return None\n    if not isinstance(data, dict):\n        return None\n    return data\n\n\ndef require_role(request: Request, role: Role) -> None:\n    data = read_session(request)\n    if not data or data.get("role") != role:\n        raise HTTPException(status_code=303, headers={"Location": f"/{role}/login"})\n\n\ndef set_login_cookie(response: Response, role: Role) -> None:\n    response.set_cookie(\n        SESSION_COOKIE,\n        make_session(role),\n        httponly=True,\n        samesite="lax",\n        secure=False,\n        max_age=60 * 60 * 24 * 30,\n    )\n\n\ndef clear_login_cookie(response: Response) -> None:\n    response.delete_cookie(SESSION_COOKIE)\n\n\ndef csrf_token(request: Request, response: Response | None = None) -> str:\n    token = request.cookies.get(CSRF_COOKIE)\n    if not token:\n        token = secrets.token_urlsafe(32)\n        if response is not None:\n            response.set_cookie(CSRF_COOKIE, token, httponly=False, samesite="lax", secure=False, max_age=60 * 60 * 24)\n    return token\n\n\ndef csrf_input(request: Request) -> str:\n    token = request.cookies.get(CSRF_COOKIE) or secrets.token_urlsafe(32)\n    return f\'<input type="hidden" name="csrf_token" value="{token}">\'\n\n\nasync def validate_csrf(request: Request) -> None:\n    cookie_token = request.cookies.get(CSRF_COOKIE)\n    try:\n        form = await request.form()\n        form_token = str(form.get("csrf_token", ""))\n    except Exception:\n        form_token = ""\n    if not cookie_token or not form_token or not secrets.compare_digest(cookie_token, form_token):\n        raise HTTPException(status_code=403, detail="CSRF validation failed")\n\n\ndef redirect(path: str) -> RedirectResponse:\n    return RedirectResponse(path, status_code=303)\n')

