_install_module('ui', 'from __future__ import annotations\n\nfrom html import escape\n\ndef e(v) -> str:\n    return escape(\'\' if v is None else str(v))\n\n\ndef layout(title: str, body: str) -> str:\n    return f\'\'\'<!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>{e(title)}</title>\n<style>\n:root{{--main:#0f766e;--main2:#0b5f59;--bg:#eef8f6;--card:#fff;--line:#d6e7e4;--text:#182426;--muted:#6b7280;--danger:#b91c1c;}}\n*{{box-sizing:border-box}} body{{margin:0;font-family:system-ui,-apple-system,Segoe UI,Tahoma,Arial,sans-serif;background:linear-gradient(180deg,#edf8f5,#f7fafc);color:var(--text)}}\n.container{{max-width:1120px;margin:0 auto;padding:22px}} .hero{{background:linear-gradient(135deg,var(--main),var(--main2));color:white;border-radius:28px;padding:28px;margin-bottom:18px;box-shadow:0 12px 30px rgba(15,118,110,.18)}}\n.hero h1{{margin:0 0 8px;font-size:32px}} .hero p{{margin:0;opacity:.9;font-size:17px}}\n.nav{{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:18px}} .nav a,.btn,button{{display:inline-flex;align-items:center;justify-content:center;gap:8px;min-height:48px;padding:12px 18px;border-radius:16px;text-decoration:none;background:#fff;border:1px solid var(--line);color:#0b5f59;font-weight:800;font-size:16px;cursor:pointer}}\n.btn,button{{background:var(--main);color:white;border:0}} .btn.secondary{{background:#fff;color:#0b5f59;border:1px solid var(--line)}} .btn.danger{{background:#b91c1c;color:white}} .btn.ok{{background:#15803d;color:white}}\n.box,.card{{background:var(--card);border:1px solid #edf2f7;border-radius:24px;padding:22px;box-shadow:0 14px 35px rgba(15,23,42,.07);margin-bottom:16px}} .grid{{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}}\n.stats{{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:16px}} .stat{{background:white;border:1px solid var(--line);border-radius:22px;padding:20px;text-align:center}} .stat b{{display:block;font-size:28px;color:var(--main)}} .stat span,.muted,.notice{{color:var(--muted)}}\n.field{{margin-bottom:14px}} label{{display:block;margin-bottom:8px;font-weight:800}} input,textarea,select{{width:100%;min-height:50px;padding:12px 14px;border-radius:16px;border:1px solid #d1d5db;font-size:16px;background:white}} textarea{{min-height:110px}}\n.actions{{display:flex;flex-wrap:wrap;gap:10px;margin-top:12px}} .row{{display:flex;justify-content:space-between;gap:14px;border-bottom:1px solid #eef2f7;padding:10px 0}} .row:last-child{{border-bottom:0}}\n.badge{{display:inline-block;padding:6px 10px;border-radius:999px;font-weight:800;background:#fef3c7;color:#92400e}} .badge.confirmed{{background:#dcfce7;color:#166534}} .badge.rejected{{background:#fee2e2;color:#991b1b}} .badge.done{{background:#dbeafe;color:#1e40af}}\n.center{{max-width:560px;margin:80px auto;text-align:center}} .product-title{{font-size:20px;font-weight:900;margin-bottom:6px}} .product-meta{{color:var(--muted);margin-bottom:12px}}\n@media(max-width:760px){{.container{{padding:18px}}.nav{{grid-template-columns:repeat(2,1fr)}}.stats{{grid-template-columns:repeat(2,1fr)}}.grid{{grid-template-columns:1fr}}.hero h1{{font-size:28px}}}}\n</style></head><body><div class="container">{body}</div></body></html>\'\'\'\n\n\ndef merchant_nav() -> str:\n    return \'\'\'<div class="nav">\n<a href="/merchant">الرئيسية 🏠</a><a href="/merchant/orders">الطلبات 🧾</a><a href="/merchant/products">المنتجات 📦</a><a href="/merchant/upload">رفع ملف ⬆️</a><a href="/merchant/analytics">الإحصائيات 📈</a><a href="/merchant/settings">الإعدادات ⚙️</a><a href="/merchant/share">رابط الزبائن 🔗</a><a href="/merchant/export/products.csv">تصدير CSV</a></div>\'\'\'\n\n\ndef admin_nav() -> str:\n    return \'\'\'<div class="nav"><a href="/admin">الرئيسية</a><a href="/admin/settings">الإعدادات</a><a href="/admin/database">قاعدة البيانات</a><a href="/admin/analytics">الإحصائيات</a><a href="/merchant">لوحة التاجر</a><a href="/health">Health</a></div>\'\'\'\n')

# ===== embedded module: app.analytics =====
_install_module('analytics', 'from __future__ import annotations\n\nimport time\nfrom .db import connect\n\n\nasync def log_inquiry(phone: str, raw_text: str, query: str, product: dict | None, found: bool) -> None:\n    async with connect() as db:\n        await db.execute(\n            """\n            INSERT INTO product_inquiries(phone, raw_text, query, product_id, product_name, found, created_at)\n            VALUES (?,?,?,?,?,?,?)\n            """,\n            (\n                phone,\n                raw_text,\n                query,\n                product.get("id") if product else None,\n                product.get("name") if product else query,\n                1 if found else 0,\n                int(time.time()),\n            ),\n        )\n        await db.commit()\n\n\nasync def top_inquiries(days: int = 1, found: int = 1, limit: int = 10) -> list[dict]:\n    since = int(time.time()) - days * 86400\n    async with connect() as db:\n        rows = await db.execute_fetchall(\n            """\n            SELECT product_name, COUNT(*) AS count\n            FROM product_inquiries\n            WHERE created_at >= ? AND found = ?\n            GROUP BY product_name\n            ORDER BY count DESC, product_name ASC\n            LIMIT ?\n            """,\n            (since, found, limit),\n        )\n        return [dict(r) for r in rows]\n')

# ===== embedded module: app.products =====
_install_module('products', 'from __future__ import annotations\n\nimport csv\nimport io\nimport time\nfrom typing import Any\nfrom openpyxl import load_workbook\n\nfrom .db import connect\nfrom .normalize import normalize, query_tokens, norm_blob\n\nPRODUCT_FIELDS = ["name", "aliases", "active_ingredient", "company", "form", "strength", "pack", "price", "available", "notes", "image"]\n\n\ndef product_blob(item: dict[str, Any]) -> str:\n    return norm_blob(\n        item.get("name"), item.get("aliases"), item.get("active_ingredient"), item.get("company"),\n        item.get("form"), item.get("strength"), item.get("pack"), item.get("notes"),\n    )\n\n\nasync def upsert_product(item: dict[str, Any]) -> int:\n    data = {k: str(item.get(k, "") or "").strip() for k in PRODUCT_FIELDS}\n    data["available"] = data.get("available") or "متوفر"\n    data["norm_blob"] = product_blob(data)\n    now = int(time.time())\n    async with connect() as db:\n        cur = await db.execute(\n            """\n            INSERT INTO products(name,aliases,active_ingredient,company,form,strength,pack,price,available,notes,image,norm_blob,updated_at)\n            VALUES (:name,:aliases,:active_ingredient,:company,:form,:strength,:pack,:price,:available,:notes,:image,:norm_blob,:updated_at)\n            """,\n            {**data, "updated_at": now},\n        )\n        await db.commit()\n        return int(cur.lastrowid)\n\n\nasync def replace_products(items: list[dict[str, Any]]) -> int:\n    async with connect() as db:\n        await db.execute("DELETE FROM products")\n        now = int(time.time())\n        for item in items:\n            data = {k: str(item.get(k, "") or "").strip() for k in PRODUCT_FIELDS}\n            if not data.get("name"):\n                continue\n            data["available"] = data.get("available") or "متوفر"\n            data["norm_blob"] = product_blob(data)\n            await db.execute(\n                """\n                INSERT INTO products(name,aliases,active_ingredient,company,form,strength,pack,price,available,notes,image,norm_blob,updated_at)\n                VALUES (:name,:aliases,:active_ingredient,:company,:form,:strength,:pack,:price,:available,:notes,:image,:norm_blob,:updated_at)\n                """,\n                {**data, "updated_at": now},\n            )\n        await db.commit()\n    return len([i for i in items if i.get("name")])\n\n\nasync def patch_product(product_id: int, values: dict[str, str]) -> None:\n    allowed = {"price", "available", "notes", "image"}\n    data = {k: str(v or "").strip() for k, v in values.items() if k in allowed}\n    if not data:\n        return\n    sets = ", ".join([f"{k}=?" for k in data]) + ", updated_at=?"\n    params = list(data.values()) + [int(time.time()), product_id]\n    async with connect() as db:\n        await db.execute(f"UPDATE products SET {sets} WHERE id=?", params)\n        await db.commit()\n\n\nasync def get_product(product_id: int) -> dict[str, Any] | None:\n    async with connect() as db:\n        cur = await db.execute("SELECT * FROM products WHERE id=?", (product_id,))\n        row = await cur.fetchone()\n        return dict(row) if row else None\n\n\nasync def search_products(text: str, limit: int = 12) -> list[dict[str, Any]]:\n    qn = normalize(text)\n    tokens = query_tokens(text)\n    async with connect() as db:\n        if qn:\n            # Direct phrase search first: name, aliases, active ingredient, then blob.\n            like = f"%{qn}%"\n            rows = await db.execute_fetchall(\n                """\n                SELECT *,\n                  CASE\n                    WHEN lower(name)=? THEN 0\n                    WHEN norm_blob LIKE ? AND active_ingredient != \'\' AND lower(active_ingredient) LIKE ? THEN 1\n                    WHEN norm_blob LIKE ? THEN 2\n                    ELSE 9\n                  END AS rank\n                FROM products\n                WHERE norm_blob LIKE ?\n                ORDER BY rank ASC, name ASC\n                LIMIT ?\n                """,\n                (qn, like, like, like, like, limit),\n            )\n            if rows:\n                return [dict(r) for r in rows]\n\n        if not tokens:\n            return []\n\n        clauses = ["norm_blob LIKE ?" for _ in tokens]\n        params = [f"%{t}%" for t in tokens]\n        rows = await db.execute_fetchall(\n            f"SELECT * FROM products WHERE {\' AND \'.join(clauses)} ORDER BY name ASC LIMIT ?",\n            (*params, limit),\n        )\n        if rows:\n            return [dict(r) for r in rows]\n\n        # Relaxed OR fallback for typos/partial words.\n        rows = await db.execute_fetchall(\n            f"SELECT * FROM products WHERE {\' OR \'.join(clauses)} ORDER BY name ASC LIMIT ?",\n            (*params, limit),\n        )\n        return [dict(r) for r in rows]\n\n\nasync def list_products(q: str = "", limit: int = 100, offset: int = 0) -> list[dict[str, Any]]:\n    qn = normalize(q)\n    async with connect() as db:\n        if qn:\n            rows = await db.execute_fetchall(\n                "SELECT * FROM products WHERE norm_blob LIKE ? ORDER BY name LIMIT ? OFFSET ?",\n                (f"%{qn}%", limit, offset),\n            )\n        else:\n            rows = await db.execute_fetchall("SELECT * FROM products ORDER BY id DESC LIMIT ? OFFSET ?", (limit, offset))\n        return [dict(r) for r in rows]\n\n\nasync def product_count() -> int:\n    async with connect() as db:\n        cur = await db.execute("SELECT COUNT(*) FROM products")\n        row = await cur.fetchone()\n        return int(row[0] if row else 0)\n\n\ndef rows_to_products(rows: list[list[str]]) -> list[dict[str, str]]:\n    if not rows:\n        return []\n    header = [normalize(str(x)).replace(" ", "_") for x in rows[0]]\n    aliases = {\n        "اسم_المنتج": "name", "الاسم": "name", "product": "name", "product_name": "name", "name": "name",\n        "بدائل": "aliases", "اسماء_بديله": "aliases", "aliases": "aliases",\n        "الماده_الفعاله": "active_ingredient", "المادة_الفعالة": "active_ingredient", "active_ingredient": "active_ingredient",\n        "الشركه": "company", "company": "company",\n        "الشكل": "form", "form": "form",\n        "التركيز": "strength", "strength": "strength",\n        "العبوه": "pack", "pack": "pack",\n        "السعر": "price", "price": "price",\n        "التوفر": "available", "available": "available",\n        "ملاحظات": "notes", "notes": "notes",\n        "صوره": "image", "image": "image",\n    }\n    mapped = [aliases.get(h, h) for h in header]\n    has_header = any(h in PRODUCT_FIELDS for h in mapped)\n    data_rows = rows[1:] if has_header else rows\n    fields = mapped if has_header else ["name", "aliases", "active_ingredient", "company", "form", "strength", "pack", "price", "available", "notes", "image"]\n    out: list[dict[str, str]] = []\n    for row in data_rows:\n        if not any(str(x).strip() for x in row):\n            continue\n        item: dict[str, str] = {}\n        for i, val in enumerate(row):\n            if i < len(fields) and fields[i] in PRODUCT_FIELDS:\n                item[fields[i]] = str(val or "").strip()\n        if item.get("name"):\n            out.append(item)\n    return out\n\n\ndef parse_upload(filename: str, content: bytes) -> list[dict[str, str]]:\n    filename = (filename or "").lower()\n    rows: list[list[str]] = []\n    if filename.endswith(".xlsx"):\n        wb = load_workbook(io.BytesIO(content), read_only=True, data_only=True)\n        ws = wb.active\n        for row in ws.iter_rows(values_only=True):\n            vals = ["" if v is None else str(v).strip() for v in row]\n            if any(vals):\n                rows.append(vals)\n    else:\n        raw = content.decode("utf-8-sig", errors="ignore")\n        for row in csv.reader(io.StringIO(raw)):\n            vals = [str(x).strip() for x in row]\n            if any(vals):\n                rows.append(vals)\n    return rows_to_products(rows)\n')

# ===== embedded module: app.orders =====
_install_module('orders', 'from __future__ import annotations\n\nimport time\nfrom typing import Any\nfrom .db import connect\n\n\nasync def create_order(phone: str, product: dict[str, Any], raw_message: str = "", media_url: str = "") -> int:\n    now = int(time.time())\n    async with connect() as db:\n        cur = await db.execute(\n            """\n            INSERT INTO orders(phone, product_id, product_name, price, notes, status, raw_message, media_url, created_at, updated_at)\n            VALUES (?,?,?,?,?,?,?,?,?,?)\n            """,\n            (\n                phone,\n                product.get("id"),\n                product.get("name", "طلب"),\n                product.get("price", ""),\n                product.get("notes", ""),\n                "pending",\n                raw_message,\n                media_url,\n                now,\n                now,\n            ),\n        )\n        await db.commit()\n        return int(cur.lastrowid)\n\n\nasync def update_order_status(order_id: int, status: str) -> dict[str, Any] | None:\n    now = int(time.time())\n    async with connect() as db:\n        await db.execute("UPDATE orders SET status=?, updated_at=? WHERE id=?", (status, now, order_id))\n        await db.commit()\n        cur = await db.execute("SELECT * FROM orders WHERE id=?", (order_id,))\n        row = await cur.fetchone()\n        return dict(row) if row else None\n\n\nasync def list_orders(status: str = "all", limit: int = 100) -> list[dict[str, Any]]:\n    async with connect() as db:\n        if status and status != "all":\n            rows = await db.execute_fetchall("SELECT * FROM orders WHERE status=? ORDER BY id DESC LIMIT ?", (status, limit))\n        else:\n            rows = await db.execute_fetchall("SELECT * FROM orders ORDER BY id DESC LIMIT ?", (limit,))\n        return [dict(r) for r in rows]\n\n\nasync def order_counts() -> dict[str, int]:\n    async with connect() as db:\n        rows = await db.execute_fetchall("SELECT status, COUNT(*) AS c FROM orders GROUP BY status")\n        total_cur = await db.execute("SELECT COUNT(*) FROM orders")\n        total = await total_cur.fetchone()\n    counts = {str(r[0]): int(r[1]) for r in rows}\n    counts["total"] = int(total[0] if total else 0)\n    return counts\n')

# ===== embedded module: app.whatsapp =====
_install_module('whatsapp', 'from __future__ import annotations\n\nimport httpx\nfrom .config import config\n\n\ndef configured() -> bool:\n    return bool(config.whatsapp_token and config.whatsapp_phone_number_id)\n\n\nasync def send_text(to: str, text: str) -> bool:\n    if not configured() or not to:\n        print("WHATSAPP_SEND_SKIPPED", to, text[:120])\n        return False\n    url = f"https://graph.facebook.com/v20.0/{config.whatsapp_phone_number_id}/messages"\n    payload = {\n        "messaging_product": "whatsapp",\n        "to": to,\n        "type": "text",\n        "text": {"preview_url": False, "body": text[:3900]},\n    }\n    headers = {"Authorization": f"Bearer {config.whatsapp_token}", "Content-Type": "application/json"}\n    async with httpx.AsyncClient(timeout=20) as client:\n        r = await client.post(url, json=payload, headers=headers)\n        if r.status_code >= 300:\n            print("WHATSAPP_SEND_ERROR", r.status_code, r.text[:500])\n            return False\n        return True\n\n\nasync def download_media(media_id: str) -> bytes | None:\n    if not configured() or not media_id:\n        return None\n    headers = {"Authorization": f"Bearer {config.whatsapp_token}"}\n    async with httpx.AsyncClient(timeout=30, follow_redirects=True) as client:\n        meta = await client.get(f"https://graph.facebook.com/v20.0/{media_id}", headers=headers)\n        if meta.status_code >= 300:\n            return None\n        url = meta.json().get("url")\n        if not url:\n            return None\n        data = await client.get(url, headers=headers)\n        if data.status_code >= 300:\n            return None\n        return data.content\n')

