_install_module('ai', 'from __future__ import annotations\n\nimport json\nimport hashlib\nimport httpx\nfrom datetime import date\nfrom .config import config\nfrom .db import get_cache, set_cache, connect\n\n\ndef split_keys(s: str) -> list[str]:\n    return [x.strip() for x in (s or "").replace(";", "\\n").replace(",", "\\n").splitlines() if x.strip()]\n\n\nasync def increment_ai_usage() -> None:\n    day = date.today().isoformat()\n    async with connect() as db:\n        await db.execute(\n            "INSERT INTO ai_usage(day,count) VALUES (?,1) ON CONFLICT(day) DO UPDATE SET count=count+1",\n            (day,),\n        )\n        await db.commit()\n\n\nasync def call_ai_json(prompt: str, image_bytes: bytes | None = None) -> dict:\n    if not config.ai_enabled:\n        return {}\n    cache_key = hashlib.sha256((prompt + str(bool(image_bytes))).encode()).hexdigest()\n    cached = await get_cache("ai_json", cache_key)\n    if cached is not None:\n        return cached\n    providers = [x.strip().lower() for x in config.provider_order.split(",") if x.strip()]\n    for provider in providers:\n        try:\n            if provider == "openrouter":\n                data = await _openrouter(prompt)\n            elif provider == "gemini":\n                data = await _gemini(prompt)\n            elif provider == "groq":\n                data = await _groq(prompt)\n            elif provider == "openai":\n                data = await _openai(prompt)\n            else:\n                continue\n            if data:\n                await set_cache("ai_json", cache_key, data)\n                await increment_ai_usage()\n                return data\n        except Exception as e:\n            print("AI_PROVIDER_ERROR", provider, e)\n            continue\n    return {}\n\n\ndef _extract_json(text: str) -> dict:\n    text = (text or "").strip()\n    start = text.find("{")\n    end = text.rfind("}")\n    if start >= 0 and end > start:\n        text = text[start:end + 1]\n    try:\n        obj = json.loads(text)\n        return obj if isinstance(obj, dict) else {}\n    except Exception:\n        return {}\n\n\nasync def _openrouter(prompt: str) -> dict:\n    keys = split_keys(config.openrouter_keys)\n    if not keys:\n        return {}\n    payload = {"model": "openrouter/auto", "messages": [{"role": "user", "content": prompt}], "temperature": 0.1}\n    async with httpx.AsyncClient(timeout=30) as client:\n        for key in keys:\n            r = await client.post("https://openrouter.ai/api/v1/chat/completions", json=payload, headers={"Authorization": f"Bearer {key}"})\n            if r.status_code < 300:\n                txt = r.json()["choices"][0]["message"]["content"]\n                return _extract_json(txt)\n    return {}\n\n\nasync def _groq(prompt: str) -> dict:\n    keys = split_keys(config.groq_keys)\n    if not keys:\n        return {}\n    payload = {"model": "llama-3.1-8b-instant", "messages": [{"role": "user", "content": prompt}], "temperature": 0.1}\n    async with httpx.AsyncClient(timeout=30) as client:\n        for key in keys:\n            r = await client.post("https://api.groq.com/openai/v1/chat/completions", json=payload, headers={"Authorization": f"Bearer {key}"})\n            if r.status_code < 300:\n                txt = r.json()["choices"][0]["message"]["content"]\n                return _extract_json(txt)\n    return {}\n\n\nasync def _openai(prompt: str) -> dict:\n    keys = split_keys(config.openai_keys)\n    if not keys:\n        return {}\n    payload = {"model": "gpt-4o-mini", "messages": [{"role": "user", "content": prompt}], "temperature": 0.1}\n    async with httpx.AsyncClient(timeout=30) as client:\n        for key in keys:\n            r = await client.post("https://api.openai.com/v1/chat/completions", json=payload, headers={"Authorization": f"Bearer {key}"})\n            if r.status_code < 300:\n                txt = r.json()["choices"][0]["message"]["content"]\n                return _extract_json(txt)\n    return {}\n\n\nasync def _gemini(prompt: str) -> dict:\n    keys = split_keys(config.gemini_keys)\n    if not keys:\n        return {}\n    body = {"contents": [{"parts": [{"text": prompt}]}], "generationConfig": {"temperature": 0.1}}\n    async with httpx.AsyncClient(timeout=30) as client:\n        for key in keys:\n            url = f"https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key={key}"\n            r = await client.post(url, json=body)\n            if r.status_code < 300:\n                parts = r.json().get("candidates", [{}])[0].get("content", {}).get("parts", [])\n                txt = "\\n".join(p.get("text", "") for p in parts)\n                return _extract_json(txt)\n    return {}\n')

