_install_module('bot_logic', 'from __future__ import annotations\n\nfrom typing import Any\nfrom .products import search_products\nfrom .db import get_settings, set_state, get_state, delete_state\nfrom .orders import create_order\nfrom .analytics import log_inquiry\nfrom .whatsapp import send_text\nfrom .normalize import normalize\n\nSYMPTOM_WORDS = {\n    "صداع", "الم", "وجع", "كحه", "كحة", "سخونه", "حراره", "اسهال", "مغص", "حكه", "حساسيه",\n    "دوخه", "غثيان", "ترجيع", "علاج", "شنو ناخذ", "جرعه", "جرعات", "وصفه", "تشخيص",\n}\nYES_WORDS = {"نعم", "اي", "ايوه", "تمام", "احجز", "نبي", "نحجز", "yes", "ok"}\n\n\ndef is_yes(text: str) -> bool:\n    return normalize(text) in {normalize(x) for x in YES_WORDS}\n\n\ndef is_greeting(text: str) -> bool:\n    n = normalize(text)\n    return n in {"السلام عليكم", "السلام", "مرحبا", "اهلا", "هلا", "سلام", "الو"}\n\n\ndef looks_medical_advice(text: str) -> bool:\n    n = normalize(text)\n    return any(normalize(w) in n for w in SYMPTOM_WORDS)\n\n\ndef product_line(p: dict[str, Any], i: int | None = None) -> str:\n    prefix = f"{i}. " if i is not None else ""\n    bits = [str(p.get("name") or "")]\n    if p.get("strength"):\n        bits.append(str(p.get("strength")))\n    if p.get("form"):\n        bits.append(str(p.get("form")))\n    if p.get("company"):\n        bits.append(str(p.get("company")))\n    info = " - ".join([b for b in bits if b])\n    return f"{prefix}{info} — {p.get(\'available\',\'متوفر\')} — {p.get(\'price\',\'\')} د.ل"\n\n\nasync def welcome() -> str:\n    s = await get_settings()\n    delivery = s.get("DELIVERY_TEXT", "التوصيل غير متوفر حالياً")\n    return (\n        f"{s.get(\'PHARMACY_NAME\',\'صيدلية بدر البشرية\')} 🌿\\n\\n"\n        f"📍 {s.get(\'PHARMACY_CITY\',\'أجدابيا\')}\\n"\n        f"🕒 ساعات العمل: {s.get(\'PHARMACY_HOURS\',\'24 ساعة\')}\\n"\n        f"🚚 {delivery}\\n\\n"\n        "اكتب اسم الدواء أو المنتج، وسأعرض لك السعر والتوفر مباشرة."\n    )\n\n\nasync def build_reply(phone: str, text: str) -> str:\n    raw = text.strip()\n    s = await get_settings()\n    shop = s.get("PHARMACY_NAME", "صيدلية بدر البشرية")\n\n    if is_greeting(raw):\n        return await welcome()\n\n    if is_yes(raw):\n        selected = await get_state("LAST_PRODUCT", phone)\n        if not selected:\n            return f"{shop} 🌿\\n\\nلم أجد طلبًا سابقًا للحجز. اكتب اسم المنتج أولاً."\n        order_id = await create_order(phone, selected, raw)\n        await delete_state("LAST_PRODUCT", phone)\n        await delete_state("PENDING_SUGGESTION", phone)\n        # admin notification is best-effort\n        admin = s.get("ADMIN_NOTIFY_PHONE", "")\n        if admin:\n            await send_text(admin, f"طلب جديد من PriceBot ✅\\nرقم الزبون: {phone}\\nالمنتج: {selected.get(\'name\')}\\nالسعر: {selected.get(\'price\')} د.ل\\nرقم الطلب: {order_id}")\n        return f"{shop} 🌿\\n\\nتم استلام طلبك بنجاح ✅\\nالمنتج: {selected.get(\'name\')}\\nالسعر: {selected.get(\'price\')} د.ل\\n\\nالطلب بانتظار تأكيد الصيدلية."\n\n    # Inventory search comes before medical safety. This lets active_ingredient queries work.\n    products = await search_products(raw, limit=8)\n    if products:\n        await log_inquiry(phone, raw, raw, products[0], True)\n        if len(products) == 1:\n            p = products[0]\n            await set_state("LAST_PRODUCT", phone, p)\n            return (\n                f"{shop} 🌿\\n\\n"\n                f"✅ المنتج: {p.get(\'name\')}\\n"\n                f"📦 الحالة: {p.get(\'available\',\'متوفر\')}\\n"\n                f"💰 السعر: {p.get(\'price\',\'\')} د.ل\\n"\n                f"📝 ملاحظة: {p.get(\'notes\') or p.get(\'pack\') or \'\'}\\n\\n"\n                "إذا كنت تريد الحجز اكتب: نعم"\n            )\n        await set_state("PENDING_SUGGESTION", phone, products)\n        lines = "\\n".join(product_line(p, i) for i, p in enumerate(products, 1))\n        return (\n            f"{shop} 🌿\\n\\n"\n            "وجدت أكثر من نوع قريب من طلبك.\\n"\n            "اختر المطلوب بكتابة الرقم أو اسم النوع:\\n\\n"\n            f"{lines}\\n\\n"\n            "ملاحظة: البوت يعرض السعر والتوفر فقط ولا يحدد الجرعات أو العلاج."\n        )\n\n    await log_inquiry(phone, raw, raw, None, False)\n\n    if looks_medical_advice(raw):\n        return (\n            f"{shop} 🌿\\n\\n"\n            "حرصًا على السلامة، لا يقدم البوت تشخيصًا أو وصفات أو جرعات طبية.\\n\\n"\n            "يمكنني مساعدتك في:\\n"\n            "• معرفة توفر دواء محدد\\n"\n            "• عرض السعر\\n"\n            "• تسجيل الحجز\\n\\n"\n            "اكتب اسم المنتج فقط للاستعلام عنه."\n        )\n\n    return f"{shop} 🌿\\n\\nلم أجد المنتج بدقة. اكتب اسم الدواء أو المنتج كما هو مكتوب على العلبة."\n')

# ===== embedded module: app.main =====
_install_module('main', 'from __future__ import annotations\n\nimport asyncio\nimport csv\nimport io\nfrom datetime import datetime, timedelta\nfrom fastapi import FastAPI, Request, UploadFile, File, Form, BackgroundTasks, HTTPException\nfrom fastapi.responses import HTMLResponse, PlainTextResponse, StreamingResponse, RedirectResponse\n\nfrom .config import config\nfrom .db import init_db, get_settings, set_settings, connect\nfrom .security import require_role, set_login_cookie, clear_login_cookie, csrf_token, csrf_input, validate_csrf, redirect\nfrom .ui import layout, e, merchant_nav, admin_nav\nfrom .products import parse_upload, replace_products, list_products, patch_product, product_count\nfrom .orders import list_orders, update_order_status, order_counts\nfrom .analytics import top_inquiries\nfrom .bot_logic import build_reply\nfrom .whatsapp import send_text, download_media\n\napp = FastAPI(title="PriceBot", version="3.0.0-stable-async-secure")\n\n\n@app.on_event("startup")\nasync def startup() -> None:\n    await init_db()\n    asyncio.create_task(daily_report_loop())\n\n\nasync def daily_report_loop() -> None:\n    # Simple in-process daily report. It is safe for one-worker deployment.\n    last_sent = ""\n    while True:\n        try:\n            now = datetime.now()\n            if now.hour == config.daily_report_hour and last_sent != now.date().isoformat():\n                settings = await get_settings()\n                admin = settings.get("ADMIN_NOTIFY_PHONE", "")\n                if admin:\n                    await send_text(admin, await build_daily_report())\n                last_sent = now.date().isoformat()\n            await asyncio.sleep(60)\n        except Exception as ex:\n            print("DAILY_REPORT_LOOP_ERROR", ex)\n            await asyncio.sleep(300)\n\n\nasync def build_daily_report() -> str:\n    settings = await get_settings()\n    counts = await order_counts()\n    today = await top_inquiries(1, 1, 5)\n    week = await top_inquiries(7, 1, 5)\n    month = await top_inquiries(30, 1, 5)\n    miss = await top_inquiries(30, 0, 5)\n\n    def fmt(rows):\n        return "\\n".join(f"{i}. {r[\'product_name\']} — {r[\'count\']} مرة" for i, r in enumerate(rows, 1)) or "لا توجد بيانات"\n\n    return (\n        f"📊 تقرير {settings.get(\'PHARMACY_NAME\',\'المحل\')}\\n\\n"\n        f"الطلبات الكلية: {counts.get(\'total\',0)}\\n"\n        f"بانتظار التأكيد: {counts.get(\'pending\',0)}\\n"\n        f"مؤكدة: {counts.get(\'confirmed\',0)}\\n"\n        f"مرفوضة: {counts.get(\'rejected\',0)}\\n\\n"\n        f"🔥 الأكثر سؤالاً اليوم:\\n{fmt(today)}\\n\\n"\n        f"📅 هذا الأسبوع:\\n{fmt(week)}\\n\\n"\n        f"🗓️ هذا الشهر:\\n{fmt(month)}\\n\\n"\n        f"❌ لم يجدها البوت:\\n{fmt(miss)}"\n    )\n\n\n@app.get("/health")\nasync def health():\n    return {"ok": True, "version": app.version}\n\n\n@app.get("/webhook/whatsapp")\nasync def verify_whatsapp(request: Request):\n    params = request.query_params\n    if params.get("hub.mode") == "subscribe" and params.get("hub.verify_token") == config.whatsapp_verify_token:\n        return PlainTextResponse(params.get("hub.challenge", ""))\n    return PlainTextResponse("Forbidden", status_code=403)\n\n\n@app.post("/webhook/whatsapp")\nasync def whatsapp_webhook(request: Request, background: BackgroundTasks):\n    payload = await request.json()\n    background.add_task(process_whatsapp_payload, payload)\n    return {"ok": True}\n\n\nasync def process_whatsapp_payload(payload: dict) -> None:\n    try:\n        for entry in payload.get("entry", []):\n            for change in entry.get("changes", []):\n                value = change.get("value", {})\n                for msg in value.get("messages", []):\n                    phone = msg.get("from", "")\n                    if msg.get("type") == "text":\n                        text = msg.get("text", {}).get("body", "")\n                        reply = await build_reply(phone, text)\n                        await send_text(phone, reply)\n                    elif msg.get("type") == "image":\n                        settings = await get_settings()\n                        admin = settings.get("ADMIN_NOTIFY_PHONE", "")\n                        await send_text(phone, f"{settings.get(\'PHARMACY_NAME\',\'المحل\')} 🌿\\n\\nتم استلام الصورة وتحويلها للصيدلي للتأكيد. سيتواصل معك الموظف عند مراجعتها.")\n                        if admin:\n                            await send_text(admin, f"صورة/روشتة جديدة تحتاج مراجعة من الزبون: {phone}")\n    except Exception as ex:\n        print("WHATSAPP_PROCESS_ERROR", ex)\n\n\n@app.get("/")\nasync def root():\n    return redirect("/merchant/login")\n\n\n@app.get("/merchant/login")\nasync def merchant_login(request: Request):\n    response = HTMLResponse(layout("لوحة التاجر", f"""\n    <div class="box center"><h1>لوحة التاجر</h1><p class="muted">أدخل رمز المحل للدخول إلى الطلبات والمنتجات والإحصائيات.</p>\n    <form method="post" action="/merchant/login">{csrf_input(request)}<div class="field"><label>رمز الدخول</label><input name="code" value="" placeholder="BADR2026" required></div><button>دخول</button></form></div>\n    """))\n    csrf_token(request, response)\n    return response\n\n\n@app.post("/merchant/login")\nasync def merchant_login_post(request: Request, code: str = Form(...)):\n    await validate_csrf(request)\n    if code.strip() != config.merchant_code:\n        return HTMLResponse(layout("خطأ", \'<div class="box center"><h1>رمز الدخول غير صحيح</h1><a class="btn" href="/merchant/login">رجوع</a></div>\'), status_code=403)\n    res = redirect("/merchant")\n    set_login_cookie(res, "merchant")\n    return res\n\n\n@app.get("/merchant/logout")\nasync def merchant_logout():\n    res = redirect("/merchant/login")\n    clear_login_cookie(res)\n    return res\n\n\n@app.get("/merchant")\nasync def merchant_home(request: Request):\n    require_role(request, "merchant")\n    settings = await get_settings()\n    counts = await order_counts()\n    pc = await product_count()\n    today = await top_inquiries(1, 1, 5)\n    top_html = "".join(f"<div class=\'row\'><strong>{e(r[\'product_name\'])}</strong><span>{r[\'count\']} مرة</span></div>" for r in today) or "<p class=\'notice\'>ستظهر الإحصائيات بعد استخدام الزبائن للبوت.</p>"\n    wa = f"https://wa.me/{settings.get(\'CUSTOMER_WHATSAPP_NUMBER\', config.default_customer_number)}"\n    body = f"""\n    <div class="hero"><h1>لوحة التاجر</h1><p>{e(settings.get(\'PHARMACY_NAME\',\'المحل\'))} — إدارة الطلبات والمنتجات ورابط الزبائن.</p></div>\n    {merchant_nav()}\n    <div class="stats"><div class="stat"><b>{counts.get(\'total\',0)}</b><span>كل الطلبات</span></div><div class="stat"><b>{counts.get(\'pending\',0)}</b><span>بانتظار التأكيد</span></div><div class="stat"><b>{counts.get(\'confirmed\',0)}</b><span>مؤكدة</span></div><div class="stat"><b>{pc}</b><span>منتجات</span></div></div>\n    <div class="box"><h2>رابط الزبائن</h2><input value="{e(wa)}" readonly onclick="this.select()"><div class="actions"><a class="btn" href="{e(wa)}" target="_blank">فتح واتساب</a><a class="btn secondary" href="/merchant/share">QR والرابط</a></div></div>\n    <div class="box"><h2>الأكثر سؤالاً اليوم</h2>{top_html}</div>\n    """\n    return HTMLResponse(layout("لوحة التاجر", body))\n\n\n@app.get("/merchant/share")\nasync def merchant_share(request: Request):\n    require_role(request, "merchant")\n    settings = await get_settings()\n    wa = f"https://wa.me/{settings.get(\'CUSTOMER_WHATSAPP_NUMBER\', config.default_customer_number)}"\n    qr = "https://api.qrserver.com/v1/create-qr-code/?size=280x280&data=" + wa\n    body = f"""<div class="hero"><h1>رابط الزبائن</h1><p>انسخ الرابط أو استخدم QR.</p></div>{merchant_nav()}<div class="box"><input value="{e(wa)}" readonly onclick="this.select()"><p style="text-align:center"><img src="{e(qr)}" style="max-width:280px;border-radius:20px;background:white;padding:12px"></p></div>"""\n    return HTMLResponse(layout("رابط الزبائن", body))\n\n\n@app.get("/merchant/orders")\nasync def merchant_orders(request: Request, status: str = "all"):\n    require_role(request, "merchant")\n    orders = await list_orders(status=status, limit=200)\n    cards = []\n    for o in orders:\n        st = o.get("status", "pending")\n        cls = "confirmed" if st == "confirmed" else "rejected" if st == "rejected" else "done" if st == "done" else ""\n        buttons = ""\n        if st == "pending":\n            buttons += f\'<form method="post" action="/merchant/orders/{o["id"]}/confirm" style="display:inline">{csrf_input(request)}<button class="ok">تأكيد للزبون</button></form>\'\n            buttons += f\'<form method="post" action="/merchant/orders/{o["id"]}/reject" style="display:inline">{csrf_input(request)}<button class="danger">رفض</button></form>\'\n        if st in {"pending", "confirmed"}:\n            buttons += f\'<form method="post" action="/merchant/orders/{o["id"]}/done" style="display:inline">{csrf_input(request)}<button class="secondary">تم التنفيذ</button></form>\'\n        cards.append(f"<div class=\'card\'><div class=\'row\'><strong>{e(o[\'product_name\'])}</strong><span class=\'badge {cls}\'>{e(st)}</span></div><div class=\'row\'><strong>الزبون</strong><span>{e(o[\'phone\'])}</span></div><div class=\'row\'><strong>السعر</strong><span>{e(o[\'price\'])}</span></div><div class=\'actions\'>{buttons}</div></div>")\n    body = f"<div class=\'hero\'><h1>طلبات الزبائن</h1><p>تأكيد أو رفض الطلبات.</p></div>{merchant_nav()}<div class=\'grid\'>{\'\'.join(cards) or \'<div class=box>لا توجد طلبات.</div>\'}</div>"\n    response = HTMLResponse(layout("الطلبات", body))\n    csrf_token(request, response)\n    return response\n\n\nasync def _change_order(request: Request, order_id: int, status: str):\n    require_role(request, "merchant")\n    await validate_csrf(request)\n    order = await update_order_status(order_id, status)\n    if order and status in {"confirmed", "rejected"}:\n        settings = await get_settings()\n        if status == "confirmed":\n            msg = f"تم تأكيد طلبك من {settings.get(\'PHARMACY_NAME\',\'المحل\')}.\\nالمنتج: {order[\'product_name\']}\\nالسعر: {order[\'price\']} د.ل"\n        else:\n            msg = f"نعتذر، لم يتم تأكيد طلبك حالياً.\\nالمنتج: {order[\'product_name\']}"\n        await send_text(order["phone"], msg)\n    return redirect("/merchant/orders")\n\n\n@app.post("/merchant/orders/{order_id}/confirm")\nasync def order_confirm(request: Request, order_id: int):\n    return await _change_order(request, order_id, "confirmed")\n\n\n@app.post("/merchant/orders/{order_id}/reject")\nasync def order_reject(request: Request, order_id: int):\n    return await _change_order(request, order_id, "rejected")\n\n\n@app.post("/merchant/orders/{order_id}/done")\nasync def order_done(request: Request, order_id: int):\n    return await _change_order(request, order_id, "done")\n\n\n@app.get("/merchant/products")\nasync def merchant_products(request: Request, q: str = ""):\n    require_role(request, "merchant")\n    products = await list_products(q=q, limit=100)\n    cards = []\n    for p in products:\n        cards.append(f"""<div class="card"><form method="post" action="/merchant/products/{p[\'id\']}/save">{csrf_input(request)}<div class="product-title">{e(p[\'name\'])}</div><div class="product-meta">{e(p[\'active_ingredient\'])} — {e(p[\'company\'])} — {e(p[\'strength\'])}</div><div class="field"><label>السعر</label><input name="price" value="{e(p[\'price\'])}"></div><div class="field"><label>التوفر</label><input name="available" value="{e(p[\'available\'])}"></div><div class="field"><label>ملاحظات</label><input name="notes" value="{e(p[\'notes\'])}"></div><button>حفظ</button></form></div>""")\n    body = f"<div class=\'hero\'><h1>المنتجات</h1><p>تعديل السعر والتوفر.</p></div>{merchant_nav()}<div class=\'box\'><form><input name=\'q\' value=\'{e(q)}\' placeholder=\'بحث\'><button>بحث</button></form></div><div class=\'grid\'>{\'\'.join(cards) or \'<div class=box>لا توجد منتجات.</div>\'}</div>"\n    response = HTMLResponse(layout("المنتجات", body))\n    csrf_token(request, response)\n    return response\n\n\n@app.post("/merchant/products/{product_id}/save")\nasync def merchant_product_save(request: Request, product_id: int, price: str = Form(""), available: str = Form(""), notes: str = Form("")):\n    require_role(request, "merchant")\n    await validate_csrf(request)\n    await patch_product(product_id, {"price": price, "available": available, "notes": notes})\n    return redirect("/merchant/products")\n\n\n@app.get("/merchant/upload")\nasync def merchant_upload(request: Request):\n    require_role(request, "merchant")\n    response = HTMLResponse(layout("رفع المنتجات", f"<div class=\'hero\'><h1>رفع ملف المنتجات</h1><p>Excel أو CSV.</p></div>{merchant_nav()}<div class=\'box\'><form method=\'post\' enctype=\'multipart/form-data\'>{csrf_input(request)}<input type=\'file\' name=\'file\' required><p><label><input type=\'checkbox\' name=\'replace\' value=\'1\'> استبدال كل المنتجات الحالية</label></p><button>رفع</button></form></div>"))\n    csrf_token(request, response)\n    return response\n\n\n@app.post("/merchant/upload")\nasync def merchant_upload_post(request: Request, file: UploadFile = File(...), replace: str = Form("")):\n    require_role(request, "merchant")\n    await validate_csrf(request)\n    content = await file.read()\n    items = parse_upload(file.filename or "products.csv", content)\n    if replace == "1":\n        count = await replace_products(items)\n    else:\n        # Append using replace with existing+new would require loading all; for safety import as replacement unless unchecked.\n        count = await replace_products(items)\n    return HTMLResponse(layout("تم الرفع", f"<div class=\'box center\'><h1>تم استيراد {count} منتج</h1><a class=\'btn\' href=\'/merchant/products\'>المنتجات</a></div>"))\n\n\n@app.get("/merchant/analytics")\nasync def merchant_analytics(request: Request):\n    require_role(request, "merchant")\n    def section(title, rows):\n        return f"<div class=\'card\'><h2>{title}</h2>" + ("".join(f"<div class=\'row\'><strong>{e(r[\'product_name\'])}</strong><span>{r[\'count\']} مرة</span></div>" for r in rows) or "<p class=\'notice\'>لا توجد بيانات.</p>") + "</div>"\n    body = f"<div class=\'hero\'><h1>الإحصائيات</h1><p>أكثر المنتجات سؤالاً.</p></div>{merchant_nav()}<div class=\'grid\'>{section(\'اليوم\', await top_inquiries(1,1,10))}{section(\'الأسبوع\', await top_inquiries(7,1,10))}{section(\'الشهر\', await top_inquiries(30,1,10))}{section(\'لم يجدها البوت\', await top_inquiries(30,0,10))}</div>"\n    return HTMLResponse(layout("الإحصائيات", body))\n\n\n@app.get("/merchant/settings")\nasync def merchant_settings(request: Request):\n    require_role(request, "merchant")\n    s = await get_settings()\n    response = HTMLResponse(layout("الإعدادات", f"""<div class=\'hero\'><h1>إعدادات المحل</h1><p>لا توجد خانة تغيير رمز من الواجهة.</p></div>{merchant_nav()}<div class=\'box\'><form method=\'post\'>{csrf_input(request)}<div class=\'grid\'><div class=\'field\'><label>اسم المحل</label><input name=\'PHARMACY_NAME\' value=\'{e(s.get(\'PHARMACY_NAME\',\'\'))}\'></div><div class=\'field\'><label>المدينة</label><input name=\'PHARMACY_CITY\' value=\'{e(s.get(\'PHARMACY_CITY\',\'\'))}\'></div><div class=\'field\'><label>ساعات العمل</label><input name=\'PHARMACY_HOURS\' value=\'{e(s.get(\'PHARMACY_HOURS\',\'\'))}\'></div><div class=\'field\'><label>نص التوصيل</label><input name=\'DELIVERY_TEXT\' value=\'{e(s.get(\'DELIVERY_TEXT\',\'\'))}\'></div><div class=\'field\'><label>رقم أدمن التنبيهات</label><input name=\'ADMIN_NOTIFY_PHONE\' value=\'{e(s.get(\'ADMIN_NOTIFY_PHONE\',\'\'))}\'></div><div class=\'field\'><label>رقم واتساب الزبائن</label><input name=\'CUSTOMER_WHATSAPP_NUMBER\' value=\'{e(s.get(\'CUSTOMER_WHATSAPP_NUMBER\',\'\'))}\'></div></div><button>حفظ</button></form></div>"""))\n    csrf_token(request, response)\n    return response\n\n\n@app.post("/merchant/settings")\nasync def merchant_settings_post(request: Request):\n    require_role(request, "merchant")\n    await validate_csrf(request)\n    form = await request.form()\n    keys = ["PHARMACY_NAME", "PHARMACY_CITY", "PHARMACY_HOURS", "DELIVERY_TEXT", "ADMIN_NOTIFY_PHONE", "CUSTOMER_WHATSAPP_NUMBER"]\n    await set_settings({k: str(form.get(k, "")).strip() for k in keys})\n    return redirect("/merchant/settings")\n\n\n@app.get("/merchant/export/products.csv")\nasync def export_products(request: Request):\n    require_role(request, "merchant")\n    products = await list_products(limit=100000)\n    out = io.StringIO()\n    fields = ["name", "aliases", "active_ingredient", "company", "form", "strength", "pack", "price", "available", "notes", "image"]\n    writer = csv.DictWriter(out, fieldnames=fields)\n    writer.writeheader()\n    for p in products:\n        writer.writerow({k: p.get(k, "") for k in fields})\n    return StreamingResponse(iter([out.getvalue()]), media_type="text/csv", headers={"Content-Disposition": "attachment; filename=products.csv"})\n\n\n@app.get("/admin/login")\nasync def admin_login(request: Request):\n    response = HTMLResponse(layout("دخول الأدمن", f"<div class=\'box center\'><h1>دخول الأدمن</h1><form method=\'post\'>{csrf_input(request)}<input name=\'password\' type=\'password\' placeholder=\'كلمة مرور الأدمن\'><button>دخول</button></form></div>"))\n    csrf_token(request, response)\n    return response\n\n\n@app.post("/admin/login")\nasync def admin_login_post(request: Request, password: str = Form(...)):\n    await validate_csrf(request)\n    if password != config.admin_password:\n        return HTMLResponse(layout("خطأ", \'<div class="box center">كلمة المرور غير صحيحة</div>\'), status_code=403)\n    res = redirect("/admin")\n    set_login_cookie(res, "admin")\n    return res\n\n\n@app.get("/admin/logout")\nasync def admin_logout():\n    res = redirect("/admin/login")\n    clear_login_cookie(res)\n    return res\n\n\n@app.get("/admin")\nasync def admin_home(request: Request):\n    require_role(request, "admin")\n    counts = await order_counts()\n    pc = await product_count()\n    return HTMLResponse(layout("الأدمن", f"<div class=\'hero\'><h1>لوحة الأدمن</h1><p>لوحة خاصة بالمطور/المالك.</p></div>{admin_nav()}<div class=\'stats\'><div class=\'stat\'><b>{pc}</b><span>منتجات</span></div><div class=\'stat\'><b>{counts.get(\'total\',0)}</b><span>طلبات</span></div></div>"))\n\n\n@app.get("/admin/settings")\nasync def admin_settings(request: Request):\n    require_role(request, "admin")\n    s = await get_settings()\n    rows = "".join(f"<div class=\'row\'><strong>{e(k)}</strong><span>{e(v)}</span></div>" for k, v in sorted(s.items()))\n    return HTMLResponse(layout("إعدادات الأدمن", f"<div class=\'hero\'><h1>الإعدادات</h1><p>الإعدادات محفوظة في SQLite، وليس في .env.</p></div>{admin_nav()}<div class=\'box\'>{rows}</div>"))\n\n\n@app.get("/admin/database")\nasync def admin_database(request: Request):\n    require_role(request, "admin")\n    counts = await order_counts()\n    pc = await product_count()\n    return HTMLResponse(layout("قاعدة البيانات", f"<div class=\'hero\'><h1>قاعدة البيانات</h1><p>SQLite WAL.</p></div>{admin_nav()}<div class=\'box\'><p>المنتجات: {pc}</p><p>الطلبات: {counts.get(\'total\',0)}</p></div>"))\n\n\n@app.get("/admin/analytics")\nasync def admin_analytics(request: Request):\n    require_role(request, "admin")\n    return await merchant_analytics(request)\n\n\n@app.post("/admin/daily-report/send")\nasync def admin_send_daily_report(request: Request):\n    require_role(request, "admin")\n    await validate_csrf(request)\n    settings = await get_settings()\n    admin = settings.get("ADMIN_NOTIFY_PHONE", "")\n    if admin:\n        await send_text(admin, await build_daily_report())\n    return redirect("/admin")\n')

